const messages = $input.all().map((item) => item.json).filter((mail) => mail && (mail.id || mail.payload || mail.snippet));
if (!messages.length) {
  return [{ json: { reply: '최근 7일 이내 받은편지함 메일이 없습니다.', action: 'gmail-summary', count: 0, items: [] } }];
}
const readHeader = (headers, key) => {
  if (!Array.isArray(headers)) return '';
  const matched = headers.find((header) => String(header.name || '').toLowerCase() === key.toLowerCase());
  return matched?.value || '';
};
const decodeSender = (value) => value || '발신자 미상';
const items = messages.slice(0, 5).map((mail, index) => {
  const headers = mail.payload?.headers || [];
  const subject = mail.subject || readHeader(headers, 'Subject') || mail.snippet || '제목 없음';
  const sender = decodeSender(mail.from?.text || readHeader(headers, 'From'));
  const snippet = (mail.snippet || '').substring(0, 120);
  const date = readHeader(headers, 'Date');
  return { index: index + 1, sender, subject, snippet, date };
});
const lines = items.map(m => `${m.index}. ${m.sender} - ${m.subject}`);
return [{ json: { reply: `최근 메일 요약입니다.\n${lines.join('\n')}`, action: 'gmail-summary', count: messages.length, items } }];
